+/** A condition accepted by conditional option helpers. */
+export type OptionCondition = string | OptionDependencyCondition | OptionDependencies;
+
+function normalizeOptionDependencies(
+  condition: OptionCondition,
+  required: boolean | undefined,
+): OptionDependencies {
+  const dependsOn = typeof condition === "string"
+    ? { option: condition }
+    : condition;
+  return required === undefined ? dependsOn : { ...dependsOn, required };
+}
+
+function normalizeFlagSpec(
+  flagSpec: OptionName | readonly OptionName[],
+): readonly OptionName[] {
+  return typeof flagSpec === "string" ? [flagSpec] : flagSpec;
+}
+
+/**
+ * Creates an option with conditional dependency metadata.
+ * @since 0.10.0
+ */
+export function conditionalOption<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser: ValueParser<M, T>,
+): Parser<M, T, ValueParserResult<T> | undefined>;
+export function conditionalOption(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+): Parser<"sync", boolean, ValueParserResult<boolean> | undefined>;
+export function conditionalOption<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  const names = normalizeFlagSpec(flagSpec);
+  const options: OptionOptions = { dependsOn: normalizeOptionDependencies(condition, undefined) };
+  return valueParser == null
+    ? option(...names, options) as Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined>
+    : option(...names, valueParser, options) as Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined>;
+}
+
+/** Creates an option whose unsatisfied dependency is a validation error. */
+export function requiredWhen<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser: ValueParser<M, T>,
+): Parser<M, T, ValueParserResult<T> | undefined>;
+export function requiredWhen(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+): Parser<"sync", boolean, ValueParserResult<boolean> | undefined>;
+export function requiredWhen<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  const dependencies = normalizeOptionDependencies(condition, true);
+  return conditionalOption(dependencies, flagSpec, valueParser as ValueParser<M, T>) as Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined>;
+}
+
+/** Creates an option that is hidden while its dependency is unsatisfied. */
+export function optionalWhen<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser: ValueParser<M, T>,
+): Parser<M, T, ValueParserResult<T> | undefined>;
+export function optionalWhen(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+): Parser<"sync", boolean, ValueParserResult<boolean> | undefined>;
+export function optionalWhen<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  const dependencies = normalizeOptionDependencies(condition, false);
+  return conditionalOption(dependencies, flagSpec, valueParser as ValueParser<M, T>) as Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined>;
+}
