+function optionTerms(usage: Usage): readonly Extract<UsageTerm, { type: "option" }>[] {
+  const terms: Extract<UsageTerm, { type: "option" }>[] = [];
+  for (const term of usage) {
+    if (term.type === "option") terms.push(term);
+    else if (term.type === "optional" || term.type === "multiple") {
+      terms.push(...optionTerms(term.terms));
+    } else if (term.type === "exclusive") {
+      for (const branch of term.terms) terms.push(...optionTerms(branch));
+    }
+  }
+  return terms;
+}
+
+function dependencyFor(usage: Usage): OptionDependencies | undefined {
+  return optionTerms(usage).find((term) => term.dependsOn)?.dependsOn;
+}
+
+function stateValue(state: unknown): unknown {
+  if (Array.isArray(state) && state.length === 1) return stateValue(state[0]);
+  if (isDependencySourceState(state)) return stateValue(state.result);
+  if (typeof state === "object" && state !== null && "success" in state) {
+    const result = state as { readonly success: boolean; readonly value?: unknown };
+    return result.success ? result.value : undefined;
+  }
+  return state;
+}
+
+function dependencySatisfied(
+  dependencies: OptionDependencies,
+  values: Readonly<Record<string | symbol, unknown>>,
+  parserPairs: readonly [string | symbol, Parser<Mode, unknown, unknown>][],
+): boolean {
+  const resolve = (condition: OptionDependencyCondition): boolean => {
+    const field = parserPairs.find(([key, parser]) =>
+      key === condition.option || optionTerms(parser.usage).some((term) =>
+        term.names.includes(condition.option as `--${string}`)
+      )
+    )?.[0];
+    if (field === undefined || !(field in values)) return false;
+    const value = values[field];
+    return Object.hasOwn(condition, "value")
+      ? value === condition.value
+      : Boolean(value);
+  };
+  const single = dependencies.option === undefined
+    ? true
+    : resolve(dependencies as OptionDependencyCondition);
+  const allOf = dependencies.allOf?.every(resolve) ?? true;
+  const anyOf = dependencies.anyOf === undefined
+    ? true
+    : dependencies.anyOf.some(resolve);
+  return single && allOf && anyOf;
+}
+
+function dependencyDescription(
+  dependencies: OptionDependencies,
+  parserPairs: readonly [string | symbol, Parser<Mode, unknown, unknown>][],
+): string {
+  const condition = dependencies.option === undefined ? dependencies.allOf?.[0] ?? dependencies.anyOf?.[0] : dependencies;
+  if (condition === undefined) return "unknown option";
+  const parser = parserPairs.find(([key, candidate]) =>
+    key === condition.option || optionTerms(candidate.usage).some((term) =>
+      term.names.includes(condition.option as `--${string}`)
+    )
+  )?.[1];
+  const names = parser === undefined ? [] : optionTerms(parser.usage).flatMap((term) => term.names);
+  const name = names.find((value) => value.startsWith("--")) ?? names[0] ?? condition.option;
+  return Object.hasOwn(condition, "value")
+    ? `${name}=${String(condition.value)}`
+    : name;
+}
